void CheckFlag()
{
    // On Linux, set via: export MY_FLAG=""
    // .NET 9 breaking change: empty env vars are no longer treated as unset.
    // Use HasEnvironmentVariable pattern to distinguish "not set" from "empty".
    var val = Environment.GetEnvironmentVariable("MY_FLAG");
    if (val == null && !IsEnvironmentVariableDefined("MY_FLAG"))
    {
        Console.WriteLine("MY_FLAG not set, using default");
    }
}

static bool IsEnvironmentVariableDefined(string variable)
{
    // In .NET 9, GetEnvironmentVariable returns "" for empty vars (previously null).
    // null now truly means "not defined".
    return Environment.GetEnvironmentVariable(variable) != null;
}

